#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int max(int a,int b){return a>b?a:b;}

void strip_newline(char *s){size_t len=strlen(s);if(len&&s[len-1]=='\n')s[len-1]='\0';}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; 
    getchar(); // consume newline after T
    while(T--){
        char s[1005], t[1005];
        if(!fgets(s,1005,stdin)) break; strip_newline(s);
        if(!fgets(t,1005,stdin)) break; strip_newline(t);
        int n=strlen(s), m=strlen(t);
        static int dp[1005][1005];
        for(int i=0;i<=n;i++) dp[i][0]=0;
        for(int j=0;j<=m;j++) dp[0][j]=0;
        for(int i=1;i<=n;i++){
            for(int j=1;j<=m;j++){
                if(s[i-1]==t[j-1]) dp[i][j]=dp[i-1][j-1]+1;
                else dp[i][j]=max(dp[i-1][j],dp[i][j-1]);
            }
        }
        printf("%d\n",dp[n][m]);
    }
    return 0;
}

