import sys

def lcs_len(s,t):
    n,m=len(s),len(t)
    dp=[[0]*(m+1) for _ in range(n+1)]
    for i in range(1,n+1):
        si=s[i-1]
        for j in range(1,m+1):
            if si==t[j-1]:
                dp[i][j]=dp[i-1][j-1]+1
            else:
                dp[i][j]=dp[i-1][j] if dp[i-1][j]>=dp[i][j-1] else dp[i][j-1]
    return dp[n][m]

data=sys.stdin.read().splitlines()
if not data:
    sys.exit()
T=int(data[0].strip())
idx=1
out=[]
for _ in range(T):
    s=data[idx].strip(); idx+=1
    t=data[idx].strip(); idx+=1
    out.append(str(lcs_len(s,t)))
print('\n'.join(out))

